76 | function timeAgo(dateStr: string) {
77 |   const diff = Date.now() - new Date(dateStr).getTime();
78 |   const mins = Math.floor(diff / 60000);
79 |   if (mins < 60) return `${mins}m ago`;
80 |   const hrs = Math.floor(mins / 60);
81 |   if (hrs < 24) return `${hrs}h ago`;
82 |   const days = Math.floor(hrs / 24);
83 |   if (days < 7) return `${days}d ago`;
84 |   return formatDate(dateStr);
85 | }
