87 | function getRoleCategory(jobTitle?: string): string {
88 |   if (!jobTitle) return "Other";
89 |   const title = jobTitle.toLowerCase();
90 |   if (title.includes("design") || title.includes("ux") || title.includes("ui")) return "Design";
91 |   if (title.includes("develop") || title.includes("frontend") || title.includes("backend") || title.includes("fullstack")) return "Development";
92 |   if (title.includes("copy") || title.includes("content") || title.includes("strateg") || title.includes("writer")) return "Content & Strategy";
93 |   if (title.includes("anima") || title.includes("video") || title.includes("photograph") || title.includes("product")) return "Production";
94 |   if (title.includes("qa") || title.includes("test")) return "Quality Assurance";
95 |   return "Other";
96 | }
