import { getAuthToken } from "@/lib/auth-cookies";

/**
 * Base URL for the backend API.
 */
const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

/**
 * Expense item interface matching backend response.
 */
export interface ApiExpense {
  id: string;
  projectId: string;
  title: string;
  category: string;
  amount: number;
  date: string;
  recordedBy: string;
  recordedByName: string;
  status: string;
  notes: string | null;
}

/**
 * Expense summary interface.
 */
export interface ExpenseSummary {
  total: number;
}

/**
 * Result of the get project expenses action.
 */
export interface GetProjectExpensesResult {
  success: boolean;
  error?: string;
  status?: number;
  expenses?: ApiExpense[];
  summary?: ExpenseSummary;
}

/**
 * Server action to get expenses for a specific project.
 *
 * @param projectId - The project ID
 */
export async function getProjectExpensesAction(
  projectId: string
): Promise<GetProjectExpensesResult> {
  const token = await getAuthToken();

  if (!token) {
    return { success: false, error: "Not authenticated", status: 401 };
  }

  try {
    const response = await fetch(
      `${API_BASE_URL}/api/projects/${projectId}/expenses`,
      {
        method: "GET",
        headers: {
          "Content-Type": "application/json",
          Cookie: `access_token=${token}`,
        },
        cache: "no-store",
      }
    );

    if (!response.ok) {
      let errorMessage = "Failed to fetch project expenses";
      try {
        const errorData = await response.json();
        errorMessage = errorData.detail || errorMessage;
      } catch {
        // ignore
      }
      return { success: false, error: errorMessage, status: response.status };
    }

    const data = await response.json();
    return { success: true, expenses: data.expenses, summary: data.summary };
  } catch (error) {
    console.error("Get project expenses error:", error);
    return { success: false, error: "An unexpected error occurred. Please try again." };
  }
}
