                      <span className="ml-2 inline-flex items-center gap-1">
                        <Lock className="h-3 w-3" /> Locked
                      </span>
                    )}
                  </span>
                </div>
                <div className="flex items-center gap-2">
                  {brief.status === "pending_approval" && (
                    <Button asChild size="sm" variant="outline">
                      <Link href={`/projects/${projectId}/brief/new`}>
                        Request Revision
                      </Link>
                    </Button>
                  )}
                  {canCreateBrief(user.role) && (
                    <Button asChild size="sm" variant="outline">
                      <Link href={`/projects/${projectId}/brief/new`}>
                        New Brief
                      </Link>
                    </Button>
                  )}
                  <Button asChild size="sm">
                    <Link href={`/projects/${projectId}/brief/${brief.id}`}>
                      View Full Brief
                      <ArrowRight className="ml-2 h-3 w-3" />
                    </Link>
                  </Button>
                </div>
              </div>
              <BriefDetail brief={brief} />
            </div>
          ) : (
            <Card>
              <CardContent className="py-8 flex flex-col items-center gap-4">
                <p className="text-center text-sm text-muted-foreground">
                  No brief created yet for this project.
                </p>
                {canCreateBrief(user.role) && (
                  <Button asChild size="sm">
                    <Link href={`/projects/${projectId}/brief/new`}>
                      New Brief
                    </Link>
                  </Button>
                )}
              </CardContent>
            </Card>
          )}
        </TabsContent>

        {/* Tasks Tab */}
        <TabsContent value="tasks" className="space-y-4">
          <Card>
            <CardContent className="py-0 px-4 space-y-3">
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium">
                  {completedTasks} of {(overviewStats ? overviewStats.tasks.total : tasks.length)} tasks completed
                </span>
                <span className="text-sm font-medium">
                  {overviewStats ? overviewStats.progress : Math.round((completedTasks / tasks.length) * 100)}%
                </span>
              </div>
              <Progress
                value={overviewStats ? overviewStats.progress : (completedTasks / tasks.length) * 100}
                className="h-2"
              />
            </CardContent>
          </Card>
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Backlog</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {overviewStats ? overviewStats.tasks.todo : tasks.filter((t) => t.status === "todo").length}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats ? overviewStats.tasks.blocked : tasks.filter((t) => t.status === "blocked").length} blocked
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>In Progress</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold text-primary">
                  {overviewStats ? overviewStats.tasks.inProgress : tasks.filter((t) => t.status === "in_progress").length}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats ? overviewStats.tasks.inReview : tasks.filter((t) => t.status === "in_review").length} in review
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Done</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {completedTasks}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats ? overviewStats.progress : Math.round((completedTasks / tasks.length) * 100)}% of total
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Logged Hours</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold tabular-nums">
                  {totalLoggedHours}
                </p>
                <p className="text-xs text-muted-foreground tabular-nums">
                  of {totalEstimatedHours}h estimated
                </p>
              </CardContent>
            </Card>
          </div>
          <TaskList
            tasks={tasks}
            action={
              <div className="flex gap-2">
                {canCreateTask(user.role) && (
                  <Button asChild size="sm">
                    <Link href={`/tasks/new?projectId=${projectId}`}>
                      New Task
                    </Link>
                  </Button>
