function formatDate(dateStr: string) {
  return new Date(dateStr).toLocaleDateString("en-IN", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });
}

function timeAgo(dateStr: string) {
  const diff = Date.now() - new Date(dateStr).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  if (days < 7) return `${days}d ago`;
  return formatDate(dateStr);
}

function getRoleCategory(jobTitle?: string): string {
  if (!jobTitle) return "Other";
  const title = jobTitle.toLowerCase();
  if (title.includes("design") || title.includes("ux") || title.includes("ui")) return "Design";
  if (title.includes("develop") || title.includes("frontend") || title.includes("backend") || title.includes("fullstack")) return "Development";
  if (title.includes("copy") || title.includes("content") || title.includes("strateg") || title.includes("writer")) return "Content & Strategy";
  if (title.includes("anima") || title.includes("video") || title.includes("photograph") || title.includes("product")) return "Production";
  if (title.includes("qa") || title.includes("test")) return "Quality Assurance";
  return "Other";
}

