      clientApprovalStatus: v.clientApprovalStatus as "pending" | "approved",
      clientApprovedBy: v.clientApprovedBy ?? undefined,
      clientApprovedAt: v.clientApprovedAt ?? undefined,
    })),
  }));
  const brief = getBriefByProject(projectId);
  const hoursByProject = getTotalHoursByProject(projectId);

  const completedMilestones = msStats ? msStats.completed : milestones.filter(
    (m) => m.status === "completed"
  ).length;
  const completedTasks = overviewStats ? overviewStats.tasks.done : tasks.filter((t) => t.status === "done").length;
  const totalLoggedHours = overviewStats ? overviewStats.time.logged : tasks.reduce((sum, t) => sum + t.loggedHours, 0);
  const totalEstimatedHours = overviewStats ? overviewStats.time.estimated : tasks.reduce(
    (sum, t) => sum + t.estimatedHours,
    0
  );

  return (
    <div className="flex flex-col gap-6 p-6">
      {/* Header */}
      <div className="flex flex-col gap-4">
        <Button asChild variant="ghost" size="sm" className="w-fit -ml-2">
          <Link href="/projects">
            <ArrowLeft className="mr-2 h-4 w-4" />
            Back to Projects
          </Link>
        </Button>

        <div className="flex flex-wrap items-start justify-between gap-4">
          <div className="space-y-1">
            <h1 className="text-2xl font-semibold">{projectName}</h1>
            <p className="text-sm text-muted-foreground max-w-2xl">
              {projectDescription}
            </p>
          </div>
          <div className="flex gap-2 items-center">
            <Badge
              variant="secondary"
              className={projectStatusColors[projectStatus]}
            >
              {formatLabel(projectStatus)}
            </Badge>
            <Badge
              variant="secondary"
              className={priorityColors[projectPriority]}
            >
              {formatLabel(projectPriority)}
            </Badge>
            <Button asChild variant="outline" size="sm">
              <Link href={`/projects/${projectId}/edit`}>
                Edit
              </Link>
            </Button>
          </div>
        </div>
      </div>

      <Separator />

      {/* Stats Row */}
      <div className={`grid gap-3 sm:grid-cols-2 ${user.role === "team_member" ? "lg:grid-cols-3" : "lg:grid-cols-4"}`}>
        <Card>
          <CardHeader className="py-0 px-4">
            <CardDescription>Client</CardDescription>
          </CardHeader>
          <CardContent className="py-0 px-4">
            <p className="text-sm font-medium">{client?.name ?? "Unknown"}</p>
            <p className="text-xs text-muted-foreground">
              {client?.industry}
            </p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="py-0 px-4">
            <CardDescription>Project Manager</CardDescription>
          </CardHeader>
          <CardContent className="py-0 px-4">
            <p className="text-sm font-medium">{pm?.name ?? "Unassigned"}</p>
            <p className="text-xs text-muted-foreground">{pm?.email}</p>
          </CardContent>
        </Card>
        {user.role !== "team_member" && (
          <Card>
            <CardHeader className="py-0 px-4">
              <CardDescription>Budget</CardDescription>
            </CardHeader>
            <CardContent className="py-0 px-4">
              <p className="text-sm font-medium">
                {formatCurrency(overviewStats ? overviewStats.budget.total : projectTotalBudget)}
              </p>
              <p className="text-xs text-muted-foreground">
                {formatCurrency(overviewStats ? overviewStats.budget.spent : budgets.reduce((sum, b) => sum + b.totalAmount, 0))} spent
              </p>
            </CardContent>
          </Card>
        )}
        <Card>
          <CardHeader className="py-0 px-4">
            <CardDescription>Timeline</CardDescription>
          </CardHeader>
          <CardContent className="py-0 px-4">
            <p className="text-sm font-medium">
              {formatDate(projectStartDate)}
            </p>
            <p className="text-xs text-muted-foreground">
              to {formatDate(projectEndDate)}
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Team */}
      <div className="flex flex-wrap items-center gap-2 text-sm">
        <Users className="h-4 w-4 text-muted-foreground" />
        <span className="text-muted-foreground">Team:</span>
        {apiTeamMembers.length > 0
          ? apiTeamMembers.map((member) => (
              <Badge key={member.id} variant="secondary">
                {member.name}
              </Badge>
            ))
          : staticTeamMembers.map(
              (member) =>
                member && (
                  <Badge key={member.id} variant="secondary">
                    {member.name}
                  </Badge>
                )
            )}
      </div>

      <Separator />

      {/* Tabs */}
      <Tabs defaultValue="brief" className="flex flex-col gap-4">
        <TabsList>
          <TabsTrigger value="brief">Brief</TabsTrigger>
          <TabsTrigger value="tasks">
            Tasks ({completedTasks}/{overviewStats ? overviewStats.tasks.total : tasks.length})
          </TabsTrigger>
          <TabsTrigger value="milestones">
            Milestones ({completedMilestones}/{overviewStats ? overviewStats.milestones.total : milestones.length})
          </TabsTrigger>
          {user.role !== "team_member" && (
            <TabsTrigger value="budget">Budget</TabsTrigger>
          )}
          {user.role !== "team_member" && (
            <TabsTrigger value="expenses">
              Expenses ({expenseItems.length})
            </TabsTrigger>
          )}
          <TabsTrigger value="activity">Activity ({apiActivities.length})</TabsTrigger>
          <TabsTrigger value="deliverables">
            Deliverables ({deliverableItems.length})
          </TabsTrigger>
          <TabsTrigger value="timesheets">
            <Clock className="mr-1 size-3" />
            Timesheets ({apiTimesheetEntries.length})
          </TabsTrigger>
          <TabsTrigger value="people">
            People ({overviewStats ? overviewStats.team.size : teamCapacityMembers.length})
          </TabsTrigger>
        </TabsList>

        {/* Brief Tab */}
        <TabsContent value="brief" className="space-y-4">
          {brief ? (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Badge variant="secondary" className={`text-[10px] ${brief.status === "approved" ? "bg-status-completed text-status-completed-foreground" : brief.status === "pending_approval" ? "bg-status-pending text-status-pending-foreground" : brief.status === "draft" ? "bg-status-draft text-status-draft-foreground" : brief.status === "revision_requested" ? "bg-status-blocked text-status-blocked-foreground" : "bg-status-cancelled text-status-cancelled-foreground"}`}>
                    {formatLabel(brief.status)}
                  </Badge>
                  <span className="text-sm text-muted-foreground">
                    {brief.versions.length} version{brief.versions.length !== 1 && "s"}
                    {brief.status === "approved" && (
                      <span className="ml-2 inline-flex items-center gap-1">
                        <Lock className="h-3 w-3" /> Locked
                      </span>
                    )}
                  </span>
                </div>
                <div className="flex items-center gap-2">
                  {brief.status === "pending_approval" && (
                    <Button asChild size="sm" variant="outline">
                      <Link href={`/projects/${projectId}/brief/new`}>
                        Request Revision
                      </Link>
                    </Button>
                  )}
                  {canCreateBrief(user.role) && (
                    <Button asChild size="sm" variant="outline">
                      <Link href={`/projects/${projectId}/brief/new`}>
                        New Brief
                      </Link>
                    </Button>
                  )}
                  <Button asChild size="sm">
                    <Link href={`/projects/${projectId}/brief/${brief.id}`}>
                      View Full Brief
                      <ArrowRight className="ml-2 h-3 w-3" />
                    </Link>
                  </Button>
                </div>
              </div>
              <BriefDetail brief={brief} />
            </div>
          ) : (
            <Card>
              <CardContent className="py-8 flex flex-col items-center gap-4">
                <p className="text-center text-sm text-muted-foreground">
                  No brief created yet for this project.
                </p>
                {canCreateBrief(user.role) && (
                  <Button asChild size="sm">
                    <Link href={`/projects/${projectId}/brief/new`}>
                      New Brief
                    </Link>
                  </Button>
                )}
              </CardContent>
            </Card>
          )}
        </TabsContent>

        {/* Tasks Tab */}
        <TabsContent value="tasks" className="space-y-4">
          <Card>
            <CardContent className="py-0 px-4 space-y-3">
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium">
                  {completedTasks} of {(overviewStats ? overviewStats.tasks.total : tasks.length)} tasks completed
                </span>
                <span className="text-sm font-medium">
                  {overviewStats ? overviewStats.progress : Math.round((completedTasks / tasks.length) * 100)}%
                </span>
              </div>
              <Progress
                value={overviewStats ? overviewStats.progress : (completedTasks / tasks.length) * 100}
                className="h-2"
              />
            </CardContent>
          </Card>
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Backlog</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {overviewStats ? overviewStats.tasks.todo : tasks.filter((t) => t.status === "todo").length}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats ? overviewStats.tasks.blocked : tasks.filter((t) => t.status === "blocked").length} blocked
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>In Progress</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold text-primary">
                  {overviewStats ? overviewStats.tasks.inProgress : tasks.filter((t) => t.status === "in_progress").length}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats ? overviewStats.tasks.inReview : tasks.filter((t) => t.status === "in_review").length} in review
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Done</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {completedTasks}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats ? overviewStats.progress : Math.round((completedTasks / tasks.length) * 100)}% of total
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Logged Hours</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold tabular-nums">
                  {totalLoggedHours}
                </p>
                <p className="text-xs text-muted-foreground tabular-nums">
                  of {totalEstimatedHours}h estimated
                </p>
              </CardContent>
            </Card>
          </div>
          <TaskList
            tasks={tasks}
            action={
              <div className="flex gap-2">
                {canCreateTask(user.role) && (
                  <Button asChild size="sm">
                    <Link href={`/tasks/new?projectId=${projectId}`}>
                      New Task
                    </Link>
                  </Button>
                )}
                <Button asChild variant="outline" size="sm">
                  <Link href={`/projects/${projectId}/tasks/kanban`}>
                    <LayoutGrid className="mr-2 h-4 w-4" />
                    Kanban View
                  </Link>
                </Button>
              </div>
            }
          />
        </TabsContent>

        {/* Milestones Tab */}
        <TabsContent value="milestones" className="space-y-4">
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Pending</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {overviewStats ? overviewStats.milestones.pending : milestones.filter((m) => m.status === "pending").length}
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>In Progress</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold text-primary">
                  {overviewStats ? overviewStats.milestones.inProgress : milestones.filter((m) => m.status === "in_progress").length}
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Completed</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {completedMilestones}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats && overviewStats.milestones.total > 0
                    ? Math.round((overviewStats.milestones.completed / overviewStats.milestones.total) * 100)
                    : milestones.length > 0
                      ? Math.round((milestones.filter((m) => m.status === "completed").length / milestones.length) * 100)
                      : 0
                  }
                  % of total
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Overdue</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {milestones.filter((m) => m.status === "overdue").length}
                </p>
              </CardContent>
            </Card>
          </div>
          <MilestoneList
            milestones={milestones}
            action={
              canCreateMilestone(user.role) ? (
                <Button asChild size="sm">
                  <Link href={`/milestones/new?projectId=${projectId}`}>
                    New Milestone
                  </Link>
                </Button>
              ) : undefined
            }
          />
        </TabsContent>

        {/* Budget Tab */}
        <TabsContent value="budget" className="space-y-4">
          <BudgetList
            budgets={budgets}
            action={
              canCreateBudget(user.role) ? (
                <Button asChild size="sm">
                  <Link href={`/budgets/new?projectId=${projectId}`}>
                    New Budget
                  </Link>
                </Button>
              ) : undefined
            }
          />
        </TabsContent>

        {/* Expenses Tab */}
        <TabsContent value="expenses" className="space-y-4">
          {showExpenseForm && canManageExpenses(user.role) && (
            <div className="rounded-lg border bg-muted/30 p-4 space-y-3">
              <p className="text-sm font-medium">Add Expense</p>
              <div className="grid gap-3 sm:grid-cols-2">
                <div className="space-y-1">
                  <Label className="text-xs">Title</Label>
                  <Input
                    placeholder="e.g. Figma License"
                    value={expenseTitle}
                    onChange={(e) => setExpenseTitle(e.target.value)}
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-xs">Category</Label>
                  <Select value={expenseCategory} onValueChange={(v) => setExpenseCategory(v as ExpenseCategory)}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {expenseCategories.map((c) => (
                        <SelectItem key={c} value={c}>
                          {formatLabel(c)}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-1">
                  <Label className="text-xs">Amount (₹)</Label>
                  <Input
                    type="number"
                    min="0"
                    step="100"
                    placeholder="e.g. 15000"
                    value={expenseAmount}
                    onChange={(e) => setExpenseAmount(e.target.value)}
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-xs">Date</Label>
                  <DatePicker
                    value={expenseDate}
                    onChange={setExpenseDate}
                    placeholder="Select date"
                  />
                </div>
              </div>
              <div className="space-y-1">
                <Label className="text-xs">Notes (optional)</Label>
                <Textarea
                  placeholder="Any additional context..."
                  value={expenseNotes}
                  onChange={(e) => setExpenseNotes(e.target.value)}
                  rows={2}
                  className="text-sm"
                />
              </div>
              <Button
                size="sm"
                onClick={handleAddExpense}
                disabled={!expenseTitle.trim() || !expenseAmount || !expenseDate}
              >
                Add Expense
              </Button>
            </div>
          )}

          <ExpenseList
            expenses={getExpensesByProject(projectId)}
            action={
              canManageExpenses(user.role) ? (
                <Button size="sm" onClick={() => setShowExpenseForm((v) => !v)}>
                  <PlusCircle className="mr-2 h-4 w-4" />
                  {showExpenseForm ? "Cancel" : "Add Expense"}
                </Button>
              ) : undefined
            }
          />
        </TabsContent>

        {/* Activity Tab */}
        <TabsContent value="activity">
          {activity.length === 0 ? (
            <p className="text-sm text-muted-foreground py-4">No activity yet.</p>
          ) : (
            <div className="space-y-1">
              {activity.map((act) => {
                return (
                  <div key={act.id} className="flex items-start gap-3 rounded-lg px-3 py-2 text-sm hover:bg-muted/50">
                    <div className="flex-1 min-w-0">
                      <p><span className="font-medium">{act.userName}</span> <span className="text-muted-foreground">{act.description}</span></p>
                    </div>
                    <span className="text-xs text-muted-foreground shrink-0">{timeAgo(act.timestamp)}</span>
                  </div>
                );
              })}
            </div>
          )}
        </TabsContent>

        {/* Deliverables Tab */}
        <TabsContent value="deliverables" className="space-y-4">
          <DeliverableList
            deliverables={deliverableItems}
            projectId={projectId}
            action={
              canCreateDeliverable(user.role) ? (
                <Button asChild size="sm">
                  <Link href={`/projects/${projectId}/deliverables/new`}>
                    New Deliverable
                  </Link>
                </Button>
              ) : undefined
            }
          />
        </TabsContent>

        {/* People Tab */}
        <TabsContent value="people" className="space-y-6">
          {teamCapacityMembers.length === 0 ? (
            <Card>
              <CardContent className="py-8">
                <p className="text-center text-sm text-muted-foreground">
                  No team members have tasks assigned yet in this project.
                </p>
              </CardContent>
            </Card>
          ) : (
            (() => {
              const roleGroups: Record<string, typeof teamCapacityMembers> = {};
              for (const member of teamCapacityMembers) {
                const category = getRoleCategory(member.user.jobTitle);
                if (!roleGroups[category]) roleGroups[category] = [];
                roleGroups[category].push(member);
              }
              const groupIcons: Record<string, React.ReactNode> = {
                Design: <Palette className="h-4 w-4 text-muted-foreground" />,
                Development: <Code className="h-4 w-4 text-muted-foreground" />,
                "Content & Strategy": <PenLine className="h-4 w-4 text-muted-foreground" />,
                Production: <Film className="h-4 w-4 text-muted-foreground" />,
                "Quality Assurance": <ShieldCheck className="h-4 w-4 text-muted-foreground" />,
                Other: <User className="h-4 w-4 text-muted-foreground" />,
              };
              return Object.entries(roleGroups).map(([category, members]) => (
                <div key={category} className="space-y-3">
                  <div className="flex items-center gap-2">
                    {groupIcons[category]}
                    <h3 className="text-sm font-semibold">{category}</h3>
                    <Badge variant="secondary" className="text-[10px] px-1.5 py-0">{members.length}</Badge>
                  </div>
                  <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
                    {members.map((member) => {
                      const barColor = member.utilizationPercent > 100 ? "bg-red-500" : member.utilizationPercent >= 80 ? "bg-yellow-500" : "bg-green-500";
                      const textColor = member.utilizationPercent > 100 ? "text-red-600" : member.utilizationPercent >= 80 ? "text-yellow-600" : "text-green-600";
                      return (
                        <Card key={member.user.id} className="gap-3">
                          <CardHeader className="pb-2">
                            <div className="flex items-start justify-between">
                              <div className="space-y-1">
                                <CardTitle className="text-base flex items-center gap-2">
                                  {member.user.name}
                                  {member.isOverloaded && (
                                    <Badge variant="destructive" className="text-[10px] px-1.5 py-0">
                                      Overloaded
                                    </Badge>
                                  )}
                                </CardTitle>
                                <div className="flex items-center gap-2">
                                  {member.user.jobTitle && (
                                    <Badge variant="secondary" className="text-[10px]">
                                      {member.user.jobTitle}
                                    </Badge>
                                  )}
                                  <span className="text-xs text-muted-foreground">{member.user.email}</span>
                                </div>
                              </div>
                            </div>
                          </CardHeader>
                          <CardContent className="space-y-3">
                            {/* Capacity bar */}
                            <div className="space-y-1">
                              <div className="flex items-center justify-between text-sm">
                                <span className="text-muted-foreground">This project</span>
                                <span className={`font-medium tabular-nums ${textColor}`}>
                                  {member.assignedHours}h / {member.capacity}h ({member.utilizationPercent}%)
                                </span>
                              </div>
                              <div className="h-2 w-full rounded-full bg-muted overflow-hidden">
                                <div className={`h-full rounded-full transition-all ${barColor}`} style={{ width: `${Math.min(member.utilizationPercent, 100)}%` }} />
                              </div>
                            </div>

                            {/* Other projects */}
                            {member.otherProjects.length > 0 && (
                              <div className="space-y-1.5 pt-1 border-t">
                                <p className="text-xs font-medium text-muted-foreground">Also working on</p>
                                <div className="flex flex-wrap gap-1.5">
                                  {member.otherProjects.map((op) => (
                                    <Link key={op.id} href={`/projects/${op.id}`}>
                                      <Badge variant="outline" className="text-xs cursor-pointer hover:bg-accent">
                                        {op.name}
                                      </Badge>
                                    </Link>
                                  ))}
                                </div>
                              </div>
                            )}
                          </CardContent>
                        </Card>
                      );
                    })}
                  </div>
                </div>
              ));
            })()
          )}
        </TabsContent>

        {/* Timesheets Tab */}
        <TabsContent value="timesheets" className="space-y-4">
          <div className="grid gap-3 sm:grid-cols-3">
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Total Hours</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold tabular-nums">{apiTimesheetSummary?.total ?? overviewStats?.time?.total ?? hoursByProject.total}h</p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Billable</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold tabular-nums text-green-600 dark:text-green-400">{apiTimesheetSummary?.billable ?? overviewStats?.time?.billable ?? hoursByProject.billable}h</p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Non-Billable</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold tabular-nums text-muted-foreground">{apiTimesheetSummary?.nonBillable ?? overviewStats?.time?.nonBillable ?? hoursByProject.nonBillable}h</p>
              </CardContent>
            </Card>
          </div>

          <div className="flex justify-end">
            <Button asChild size="sm">
              <Link href={`/timesheets/new?projectId=${projectId}`}>
                <PlusCircle className="mr-2 h-4 w-4" />
                Log Time
              </Link>
            </Button>
          </div>

          {apiTimesheetEntries.length === 0 ? (
            <Card>
              <CardContent className="py-8">
                <p className="text-center text-sm text-muted-foreground">
                  No timesheet entries for this project yet.
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="rounded-lg border">
              <div className="grid grid-cols-12 items-center gap-4 border-b bg-muted/40 px-4 py-2 text-[11px] font-semibold uppercase tracking-wide text-muted-foreground">
