  useEffect(() => {
    if (overviewStats) {
      document.title = `${overviewStats.name} | Project Manager`;
    } else if (project) {
      document.title = `${project.name} | Project Manager`;
    }
  }, [project, overviewStats]);

  // Fetch overview stats from API (includes project header data)
  useEffect(() => {
    async function fetchOverviewStats() {
      if (!params.id) return;
      const result = await getProjectOverviewStatsAction(params.id as string);
      if (result.success && result.data) {
        setOverviewStats(result.data);
      }
    }
    fetchOverviewStats();
  }, [params.id]);

  // Fetch client data from API (fallback if overview stats doesn't include client)
  useEffect(() => {
    async function fetchClient() {
      if (overviewStats?.client) return; // Already have client from overview stats
      const fallbackClientId = overviewStats?.client?.id ?? project?.clientId;
      if (!fallbackClientId) return;
      setClientLoading(true);
      const result = await getClientAction(fallbackClientId);
      if (result.success && result.client) {
        setClientData(result.client);
      }
      setClientLoading(false);
    }
    fetchClient();
  }, [project?.clientId, overviewStats?.client]);

  // Fetch project tasks from API
  useEffect(() => {
    async function fetchProjectTasks() {
      if (!params.id) return;
      const result = await getProjectTasksAction(params.id as string);
      if (result.success && result.tasks) {
        setProjectTasks(result.tasks.map((t) => ({
          id: t.id,
          projectId: t.projectId,
          milestoneId: t.milestoneId,
          title: t.title,
          description: t.description ?? "",
          assignedTo: t.assignedTo,
          status: t.status as TaskStatus,
          priority: t.priority as TaskPriority,
          estimatedHours: t.estimatedHours ?? 0,
          loggedHours: t.loggedHours ?? 0,
          dueDate: t.dueDate ?? "",
          tags: t.tags,
        })));
      }
    }
    fetchProjectTasks();
  }, [project?.id]);

  useEffect(() => {
    async function fetchTeamCapacity() {
      if (!params.id) return;
      const result = await getProjectTeamCapacityAction(params.id as string);
      if (result.success && result.members) {
        setTeamCapacityMembers(result.members);
      }
    }
    fetchTeamCapacity();
  }, [params.id]);

  useEffect(() => {
    async function fetchMilestones() {
      if (!params.id) return;
      const result = await getProjectMilestonesAction(params.id as string);
      if (result.success && result.milestones) {
        setProjectMilestones(result.milestones);
      }
      if (result.success && result.stats) {
        setMilestoneStats(result.stats);
      }
    }
    fetchMilestones();
  }, [params.id]);

  useEffect(() => {
    async function fetchTimesheets() {
      if (!params.id) return;
      const result = await getProjectTimesheetsAction(params.id as string);
      if (result.success) {
        if (result.entries) setApiTimesheetEntries(result.entries);
        if (result.summary) setApiTimesheetSummary(result.summary);
      }
    }
    fetchTimesheets();
  }, [params.id]);

  useEffect(() => {
    async function fetchDeliverables() {
      if (!params.id) return;
      const result = await getProjectDeliverablesAction(params.id as string);
      if (result.success && result.deliverables) {
        setApiDeliverables(result.deliverables);
      }
    }
    fetchDeliverables();
  }, [params.id]);

  useEffect(() => {
    async function fetchActivities() {
      if (!params.id) return;
      const result = await getProjectActivityAction(params.id as string);
      if (result.success && result.activities) {
        setApiActivities(result.activities);
      }
    }
    fetchActivities();
  }, [params.id]);

  // Expense form state
  const [showExpenseForm, setShowExpenseForm] = useState(false);
  const [expenseTitle, setExpenseTitle] = useState("");
  const [expenseCategory, setExpenseCategory] = useState<ExpenseCategory>("other");
  const [expenseAmount, setExpenseAmount] = useState("");
  const [expenseDate, setExpenseDate] = useState("");
  const [expenseNotes, setExpenseNotes] = useState("");

  const expenseCategories: ExpenseCategory[] = [
    "design", "development", "production", "strategy",
    "materials", "software", "travel", "other",
  ];

  function handleAddExpense() {
    if (!user || !params.id) return;
    if (!expenseTitle.trim() || !expenseAmount || !expenseDate) return;
    addExpense({
      projectId: params.id as string,
      title: expenseTitle.trim(),
      category: expenseCategory,
      amount: Number(expenseAmount),
      date: expenseDate,
      recordedBy: user.id,
      notes: expenseNotes.trim() || undefined,
    });
    setExpenseTitle("");
    setExpenseCategory("other");
    setExpenseAmount("");
    setExpenseDate("");
    setExpenseNotes("");
    setShowExpenseForm(false);
  }

  if (isLoading || !user) {
    return (
      <div className="flex flex-1 items-center justify-center">
        <p className="text-muted-foreground">Loading...</p>
      </div>
    );
  }

  if (!project && !overviewStats) {
    return (
      <div className="flex flex-1 flex-col items-center justify-center gap-4">
        <p className="text-muted-foreground">Project not found.</p>
        <Button asChild variant="outline">
          <Link href="/projects">
            <ArrowLeft className="mr-2 h-4 w-4" />
            Back to Projects
          </Link>
        </Button>
      </div>
    );
  }

  // Use API data from overviewStats for header, fall back to static data
  const projectName = overviewStats?.name ?? project?.name ?? "";
  const projectDescription = overviewStats?.description ?? project?.description ?? "";
  const projectStatus = overviewStats?.status ?? project?.status ?? "";
  const projectPriority = overviewStats?.priority ?? project?.priority ?? "";
  const projectStartDate = overviewStats?.startDate ?? project?.startDate ?? "";
  const projectEndDate = overviewStats?.endDate ?? project?.endDate ?? "";
  const projectTotalBudget = overviewStats?.totalBudget ?? project?.totalBudget ?? 0;
  const projectCurrency = overviewStats?.currency ?? project?.currency ?? "INR";
  const projectTags = overviewStats?.tags ?? project?.tags ?? [];
  const projectId = overviewStats?.projectId ?? project?.id ?? "";

  // Client: prefer API data, fall back to separate client fetch
  const client = overviewStats?.client ?? clientData;
  // Project Manager: prefer API data, fall back to static
  const pm = overviewStats?.projectManager ?? (project ? getUserById(project.projectManagerId) : undefined);
  // Team members: prefer API data, fall back to static
  const apiTeamMembers: OverviewTeamMemberInfo[] = overviewStats?.teamMembers ?? [];
  const staticTeamMembers = project
    ? project.teamMemberIds.map((id) => getUserById(id)).filter(Boolean)
    : [];

  const milestones = projectMilestones;
  const msStats = milestoneStats;
  const tasks = projectTasks;
  const budgets = getBudgetsByProject(projectId);
  const expenseItems = apiExpenses;
  const activity = apiActivities;
  const deliverableItems: (Deliverable & { assignedToName?: string; approvedByName?: string })[] = apiDeliverables.map((d) => ({
    id: d.id,
    projectId: d.projectId,
    milestoneId: d.milestoneId,
    taskId: d.taskId,
    title: d.title,
    description: d.description,
    assignedTo: d.assignedTo,
    assignedToName: d.assignedToName,
    status: d.status as "in_progress" | "in_review" | "approved" | "revision_requested",
    currentVersion: d.currentVersion,
    approvedBy: d.approvedBy ?? undefined,
    approvedByName: d.approvedByName ?? undefined,
    approvedAt: d.approvedAt ?? undefined,
    versions: d.versions.map((v) => ({
      version: v.version,
      uploadedBy: v.uploadedBy,
      uploadedAt: v.uploadedAt,
      note: v.note,
      fileUrl: v.fileUrl,
      agencyApprovalStatus: v.agencyApprovalStatus as "pending" | "approved",
      agencyApprovedBy: v.agencyApprovedBy ?? undefined,
      agencyApprovedAt: v.agencyApprovedAt ?? undefined,
      clientApprovalStatus: v.clientApprovalStatus as "pending" | "approved",
      clientApprovedBy: v.clientApprovedBy ?? undefined,
      clientApprovedAt: v.clientApprovedAt ?? undefined,
    })),
  }));
  const brief = getBriefByProject(projectId);
  const hoursByProject = getTotalHoursByProject(projectId);

  const completedMilestones = msStats ? msStats.completed : milestones.filter(
    (m) => m.status === "completed"
  ).length;
  const completedTasks = overviewStats ? overviewStats.tasks.done : tasks.filter((t) => t.status === "done").length;
  const totalLoggedHours = overviewStats ? overviewStats.time.logged : tasks.reduce((sum, t) => sum + t.loggedHours, 0);
  const totalEstimatedHours = overviewStats ? overviewStats.time.estimated : tasks.reduce(
    (sum, t) => sum + t.estimatedHours,
    0
  );

  return (
    <div className="flex flex-col gap-6 p-6">
      {/* Header */}
      <div className="flex flex-col gap-4">
        <Button asChild variant="ghost" size="sm" className="w-fit -ml-2">
          <Link href="/projects">
            <ArrowLeft className="mr-2 h-4 w-4" />
            Back to Projects
          </Link>
        </Button>

        <div className="flex flex-wrap items-start justify-between gap-4">
          <div className="space-y-1">
            <h1 className="text-2xl font-semibold">{projectName}</h1>
            <p className="text-sm text-muted-foreground max-w-2xl">
              {projectDescription}
            </p>
          </div>
          <div className="flex gap-2 items-center">
            <Badge
              variant="secondary"
              className={projectStatusColors[projectStatus]}
            >
              {formatLabel(projectStatus)}
            </Badge>
            <Badge
              variant="secondary"
              className={priorityColors[projectPriority]}
            >
              {formatLabel(projectPriority)}
            </Badge>
            <Button asChild variant="outline" size="sm">
              <Link href={`/projects/${projectId}/edit`}>
                Edit
              </Link>
            </Button>
          </div>
        </div>
      </div>

      <Separator />

      {/* Stats Row */}
      <div className={`grid gap-3 sm:grid-cols-2 ${user.role === "team_member" ? "lg:grid-cols-3" : "lg:grid-cols-4"}`}>
        <Card>
          <CardHeader className="py-0 px-4">
            <CardDescription>Client</CardDescription>
          </CardHeader>
          <CardContent className="py-0 px-4">
            <p className="text-sm font-medium">{client?.name ?? "Unknown"}</p>
            <p className="text-xs text-muted-foreground">
              {client?.industry}
            </p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="py-0 px-4">
            <CardDescription>Project Manager</CardDescription>
          </CardHeader>
          <CardContent className="py-0 px-4">
            <p className="text-sm font-medium">{pm?.name ?? "Unassigned"}</p>
            <p className="text-xs text-muted-foreground">{pm?.email}</p>
          </CardContent>
        </Card>
        {user.role !== "team_member" && (
          <Card>
            <CardHeader className="py-0 px-4">
              <CardDescription>Budget</CardDescription>
            </CardHeader>
            <CardContent className="py-0 px-4">
              <p className="text-sm font-medium">
                {formatCurrency(overviewStats ? overviewStats.budget.total : projectTotalBudget)}
              </p>
              <p className="text-xs text-muted-foreground">
                {formatCurrency(overviewStats ? overviewStats.budget.spent : budgets.reduce((sum, b) => sum + b.totalAmount, 0))} spent
              </p>
            </CardContent>
          </Card>
        )}
        <Card>
          <CardHeader className="py-0 px-4">
            <CardDescription>Timeline</CardDescription>
          </CardHeader>
          <CardContent className="py-0 px-4">
            <p className="text-sm font-medium">
              {formatDate(projectStartDate)}
            </p>
            <p className="text-xs text-muted-foreground">
              to {formatDate(projectEndDate)}
            </p>
          </CardContent>
        </Card>
      </div>

      {/* Team */}
      <div className="flex flex-wrap items-center gap-2 text-sm">
        <Users className="h-4 w-4 text-muted-foreground" />
        <span className="text-muted-foreground">Team:</span>
        {apiTeamMembers.length > 0
          ? apiTeamMembers.map((member) => (
              <Badge key={member.id} variant="secondary">
                {member.name}
              </Badge>
            ))
          : staticTeamMembers.map(
              (member) =>
                member && (
                  <Badge key={member.id} variant="secondary">
                    {member.name}
                  </Badge>
                )
            )}
      </div>

      <Separator />

      {/* Tabs */}
      <Tabs defaultValue="brief" className="flex flex-col gap-4">
        <TabsList>
          <TabsTrigger value="brief">Brief</TabsTrigger>
          <TabsTrigger value="tasks">
            Tasks ({completedTasks}/{overviewStats ? overviewStats.tasks.total : tasks.length})
          </TabsTrigger>
          <TabsTrigger value="milestones">
            Milestones ({completedMilestones}/{overviewStats ? overviewStats.milestones.total : milestones.length})
          </TabsTrigger>
          {user.role !== "team_member" && (
            <TabsTrigger value="budget">Budget</TabsTrigger>
          )}
          {user.role !== "team_member" && (
            <TabsTrigger value="expenses">
              Expenses ({expenseItems.length})
            </TabsTrigger>
          )}
          <TabsTrigger value="activity">Activity ({apiActivities.length})</TabsTrigger>
          <TabsTrigger value="deliverables">
            Deliverables ({deliverableItems.length})
          </TabsTrigger>
          <TabsTrigger value="timesheets">
            <Clock className="mr-1 size-3" />
            Timesheets ({apiTimesheetEntries.length})
          </TabsTrigger>
          <TabsTrigger value="people">
            People ({overviewStats ? overviewStats.team.size : teamCapacityMembers.length})
          </TabsTrigger>
        </TabsList>

        {/* Brief Tab */}
        <TabsContent value="brief" className="space-y-4">
          {brief ? (
            <div className="space-y-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Badge variant="secondary" className={`text-[10px] ${brief.status === "approved" ? "bg-status-completed text-status-completed-foreground" : brief.status === "pending_approval" ? "bg-status-pending text-status-pending-foreground" : brief.status === "draft" ? "bg-status-draft text-status-draft-foreground" : brief.status === "revision_requested" ? "bg-status-blocked text-status-blocked-foreground" : "bg-status-cancelled text-status-cancelled-foreground"}`}>
                    {formatLabel(brief.status)}
                  </Badge>
                  <span className="text-sm text-muted-foreground">
                    {brief.versions.length} version{brief.versions.length !== 1 && "s"}
                    {brief.status === "approved" && (
                      <span className="ml-2 inline-flex items-center gap-1">
                        <Lock className="h-3 w-3" /> Locked
                      </span>
                    )}
                  </span>
                </div>
                <div className="flex items-center gap-2">
                  {brief.status === "pending_approval" && (
                    <Button asChild size="sm" variant="outline">
                      <Link href={`/projects/${projectId}/brief/new`}>
                        Request Revision
                      </Link>
                    </Button>
                  )}
                  {canCreateBrief(user.role) && (
                    <Button asChild size="sm" variant="outline">
                      <Link href={`/projects/${projectId}/brief/new`}>
                        New Brief
                      </Link>
                    </Button>
                  )}
                  <Button asChild size="sm">
                    <Link href={`/projects/${projectId}/brief/${brief.id}`}>
                      View Full Brief
                      <ArrowRight className="ml-2 h-3 w-3" />
                    </Link>
                  </Button>
                </div>
              </div>
              <BriefDetail brief={brief} />
            </div>
          ) : (
            <Card>
              <CardContent className="py-8 flex flex-col items-center gap-4">
                <p className="text-center text-sm text-muted-foreground">
                  No brief created yet for this project.
                </p>
                {canCreateBrief(user.role) && (
                  <Button asChild size="sm">
                    <Link href={`/projects/${projectId}/brief/new`}>
                      New Brief
                    </Link>
                  </Button>
                )}
              </CardContent>
            </Card>
          )}
        </TabsContent>

        {/* Tasks Tab */}
        <TabsContent value="tasks" className="space-y-4">
          <Card>
            <CardContent className="py-0 px-4 space-y-3">
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium">
                  {completedTasks} of {(overviewStats ? overviewStats.tasks.total : tasks.length)} tasks completed
                </span>
                <span className="text-sm font-medium">
                  {overviewStats ? overviewStats.progress : Math.round((completedTasks / tasks.length) * 100)}%
                </span>
              </div>
              <Progress
                value={overviewStats ? overviewStats.progress : (completedTasks / tasks.length) * 100}
                className="h-2"
              />
            </CardContent>
          </Card>
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Backlog</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {overviewStats ? overviewStats.tasks.todo : tasks.filter((t) => t.status === "todo").length}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats ? overviewStats.tasks.blocked : tasks.filter((t) => t.status === "blocked").length} blocked
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>In Progress</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold text-primary">
                  {overviewStats ? overviewStats.tasks.inProgress : tasks.filter((t) => t.status === "in_progress").length}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats ? overviewStats.tasks.inReview : tasks.filter((t) => t.status === "in_review").length} in review
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Done</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {completedTasks}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats ? overviewStats.progress : Math.round((completedTasks / tasks.length) * 100)}% of total
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Logged Hours</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold tabular-nums">
                  {totalLoggedHours}
                </p>
                <p className="text-xs text-muted-foreground tabular-nums">
                  of {totalEstimatedHours}h estimated
                </p>
              </CardContent>
            </Card>
          </div>
          <TaskList
            tasks={tasks}
            action={
              <div className="flex gap-2">
                {canCreateTask(user.role) && (
                  <Button asChild size="sm">
                    <Link href={`/tasks/new?projectId=${projectId}`}>
                      New Task
                    </Link>
                  </Button>
                )}
                <Button asChild variant="outline" size="sm">
                  <Link href={`/projects/${projectId}/tasks/kanban`}>
                    <LayoutGrid className="mr-2 h-4 w-4" />
                    Kanban View
                  </Link>
                </Button>
              </div>
            }
          />
        </TabsContent>

        {/* Milestones Tab */}
        <TabsContent value="milestones" className="space-y-4">
          <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-4">
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Pending</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {overviewStats ? overviewStats.milestones.pending : milestones.filter((m) => m.status === "pending").length}
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>In Progress</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold text-primary">
                  {overviewStats ? overviewStats.milestones.inProgress : milestones.filter((m) => m.status === "in_progress").length}
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Completed</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {completedMilestones}
                </p>
                <p className="text-xs text-muted-foreground">
                  {overviewStats && overviewStats.milestones.total > 0
                    ? Math.round((overviewStats.milestones.completed / overviewStats.milestones.total) * 100)
                    : milestones.length > 0
                      ? Math.round((milestones.filter((m) => m.status === "completed").length / milestones.length) * 100)
                      : 0
                  }
                  % of total
                </p>
              </CardContent>
            </Card>
            <Card className="gap-2">
              <CardHeader className="py-0 px-4">
                <CardDescription>Overdue</CardDescription>
              </CardHeader>
              <CardContent className="py-0 px-4">
                <p className="text-2xl font-semibold">
                  {milestones.filter((m) => m.status === "overdue").length}
                </p>
              </CardContent>
            </Card>
          </div>
          <MilestoneList
            milestones={milestones}
            action={
              canCreateMilestone(user.role) ? (
                <Button asChild size="sm">
                  <Link href={`/milestones/new?projectId=${projectId}`}>
                    New Milestone
                  </Link>
                </Button>
              ) : undefined
            }
          />
        </TabsContent>

        {/* Budget Tab */}
        <TabsContent value="budget" className="space-y-4">
          <BudgetList
            budgets={budgets}
            action={
              canCreateBudget(user.role) ? (
                <Button asChild size="sm">
                  <Link href={`/budgets/new?projectId=${projectId}`}>
                    New Budget
                  </Link>
                </Button>
              ) : undefined
            }
          />
        </TabsContent>

        {/* Expenses Tab */}
        <TabsContent value="expenses" className="space-y-4">
          {showExpenseForm && canManageExpenses(user.role) && (
            <div className="rounded-lg border bg-muted/30 p-4 space-y-3">
              <p className="text-sm font-medium">Add Expense</p>
              <div className="grid gap-3 sm:grid-cols-2">
                <div className="space-y-1">
                  <Label className="text-xs">Title</Label>
                  <Input
                    placeholder="e.g. Figma License"
                    value={expenseTitle}
                    onChange={(e) => setExpenseTitle(e.target.value)}
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-xs">Category</Label>
                  <Select value={expenseCategory} onValueChange={(v) => setExpenseCategory(v as ExpenseCategory)}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      {expenseCategories.map((c) => (
                        <SelectItem key={c} value={c}>
                          {formatLabel(c)}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-1">
                  <Label className="text-xs">Amount (₹)</Label>
                  <Input
                    type="number"
                    min="0"
                    step="100"
                    placeholder="e.g. 15000"
                    value={expenseAmount}
                    onChange={(e) => setExpenseAmount(e.target.value)}
                  />
                </div>
                <div className="space-y-1">
                  <Label className="text-xs">Date</Label>
                  <DatePicker
                    value={expenseDate}
                    onChange={setExpenseDate}
                    placeholder="Select date"
                  />
                </div>
              </div>
              <div className="space-y-1">
                <Label className="text-xs">Notes (optional)</Label>
                <Textarea
                  placeholder="Any additional context..."
                  value={expenseNotes}
                  onChange={(e) => setExpenseNotes(e.target.value)}
                  rows={2}
                  className="text-sm"
                />
              </div>
              <Button
                size="sm"
                onClick={handleAddExpense}
                disabled={!expenseTitle.trim() || !expenseAmount || !expenseDate}
              >
                Add Expense
              </Button>
            </div>
          )}

          <ExpenseList
            expenses={expenseItems}
            action={
              canManageExpenses(user.role) ? (
                <Button size="sm" onClick={() => setShowExpenseForm((v) => !v)}>
                  <PlusCircle className="mr-2 h-4 w-4" />
                  {showExpenseForm ? "Cancel" : "Add Expense"}
                </Button>
              ) : undefined
            }
          />
        </TabsContent>

        {/* Activity Tab */}
        <TabsContent value="activity">
          {activity.length === 0 ? (
