<final_file_content path="frontend/components/projects/expense-list.tsx">
"use client";

import { useState, useMemo } from "react";
import { getUserById } from "@/data/users";
import {
  formatCurrency,
  formatLabel,
  expenseStatusColors,
} from "@/lib/utils";
type ExpenseStatus = "submitted" | "verified" | "disputed";
type ExpenseCategory =
  | "design"
  | "development"
  | "production"
  | "strategy"
  | "materials"
  | "software"
  | "travel"
  | "other";

interface Expense {
  id: string;
  projectId: string;
  title: string;
  category: ExpenseCategory;
  amount: number;
  date: string;
  recordedBy: string;
  status: ExpenseStatus;
  notes?: string | null;
}
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Button } from "@/components/ui/button";
import {
  CircleDot,
  CheckCircle2,
  AlertCircle,
  Calendar,
  User,
  ListFilter,
  X,
} from "lucide-react";
import { Badge } from "@/components/ui/badge";

function formatDate(dateStr: string) {
  return new Date(dateStr).toLocaleDateString("en-IN", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });
}

const statusIcons: Record<string, React.ReactNode> = {
  submitted: <CircleDot className="size-4 text-priority-medium" />,
  verified: <CheckCircle2 className="size-4 text-status-completed-foreground" />,
  disputed: <AlertCircle className="size-4 text-status-blocked-foreground" />,
};

const statuses: (ExpenseStatus | "all")[] = [
  "all",
  "submitted",
  "verified",
  "disputed",
];

const categories: (ExpenseCategory | "all")[] = [
  "all",
  "design",
  "development",
  "production",
  "strategy",
  "materials",
  "software",
  "travel",
  "other",
];

export function ExpenseList({ expenses, action }: { expenses: Expense[]; action?: React.ReactNode }) {
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [categoryFilter, setCategoryFilter] = useState<string>("all");

  const filteredExpenses = useMemo(() => {
    return expenses.filter((e) => {
      if (statusFilter !== "all" && e.status !== statusFilter) return false;
      if (categoryFilter !== "all" && e.category !== categoryFilter) return false;
      return true;
    });
  }, [expenses, statusFilter, categoryFilter]);

  const totalVerified = expenses
    .filter((e) => e.status === "verified")
    .reduce((sum, e) => sum + e.amount, 0);

  const totalSubmitted = expenses
    .filter((e) => e.status === "submitted")
    .reduce((sum, e) => sum + e.amount, 0);

  const totalDisputed = expenses
    .filter((e) => e.status === "disputed")
    .reduce((sum, e) => sum + e.amount, 0);

  const totalAll = expenses.reduce((sum, e) => sum + e.amount, 0);

  if (expenses.length === 0) {
    return (
      <p className="py-6 text-center text-sm text-muted-foreground">
        No expenses recorded yet.
      </p>
    );
  }

  return (
    <div className="flex flex-col gap-3">
      {/* Summary + Filters */}
      <div className="flex flex-wrap items-center gap-4">
        <div className="flex items-center gap-2">
          <ListFilter className="size-4 text-muted-foreground" />

          <Select value={statusFilter} onValueChange={setStatusFilter}>
            <SelectTrigger size="sm" className="w-[140px]">
              <SelectValue placeholder="Status" />
            </SelectTrigger>
            <SelectContent>
              {statuses.map((s) => (
                <SelectItem key={s} value={s}>
                  {s === "all" ? "All Statuses" : formatLabel(s)}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          <Select value={categoryFilter} onValueChange={setCategoryFilter}>
            <SelectTrigger size="sm" className="w-[140px]">
              <SelectValue placeholder="Category" />
            </SelectTrigger>
            <SelectContent>
              {categories.map((c) => (
                <SelectItem key={c} value={c}>
                  {c === "all" ? "All Categories" : formatLabel(c)}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          {(statusFilter !== "all" || categoryFilter !== "all") && (
            <Button
              variant="ghost"
              size="sm"
              className="h-7 px-2 text-muted-foreground"
              onClick={() => {
                setStatusFilter("all");
                setCategoryFilter("all");
              }}
            >
              <X className="size-3" />
              Clear
            </Button>
          )}
        </div>

        {action && <span className="ml-auto">{action}</span>}

        <div className="flex items-center gap-4 text-xs text-muted-foreground">
          <span className="tabular-nums">
            {formatCurrency(totalAll)} total
          </span>
          {totalDisputed > 0 && (
            <span className="text-status-blocked-foreground font-medium">
              {formatCurrency(totalDisputed)} disputed
            </span>
          )}
          <span className="tabular-nums">
            {filteredExpenses.length} of {expenses.length} expenses
          </span>
        </div>
      </div>

      {/* Table */}
      <div className="rounded-lg border">
        {/* Column Headers */}
        <div className="grid grid-cols-12 items-center gap-4 border-b bg-muted/40 px-4 py-2.5 text-[11px] font-semibold uppercase tracking-wide text-muted-foreground">
          <div className="col-span-4 min-w-0">Expense</div>
          <div className="col-span-2 hidden sm:block">Category</div>
          <div className="col-span-1 hidden sm:block">Status</div>
          <div className="col-span-2 hidden md:block text-right">Amount</div>
          <div className="col-span-2 hidden lg:block">Date</div>
          <div className="col-span-1 hidden lg:block">Recorded By</div>
        </div>

        {/* Expense Rows */}
        {filteredExpenses.length === 0 ? (
          <div className="py-8 text-center text-sm text-muted-foreground">
            No expenses match the current filter.
          </div>
        ) : (
          <div className="divide-y">
            {filteredExpenses.map((expense) => {
              const isDisputed = expense.status === "disputed";
              const recordedBy = getUserById(expense.recordedBy);

              return (
                <div
                  key={expense.id}
                  className={`grid grid-cols-12 items-center gap-4 px-4 py-3 ${
                    isDisputed
                      ? "bg-status-blocked/10 hover:bg-status-blocked/15"
                      : "hover:bg-muted/40"
                  } transition-colors`}
                >
                  {/* Title + notes */}
                  <div className="col-span-4 min-w-0">
                    <span className="text-sm font-medium">{expense.title}</span>
                    {expense.notes && (
                      <p className="mt-0.5 truncate text-xs text-muted-foreground">
                        {expense.notes}
                      </p>
                    )}
                  </div>

                  {/* Category */}
                  <div className="col-span-2 hidden sm:block">
                    <Badge variant="outline" className="text-[10px] font-normal capitalize">
                      {expense.category}
                    </Badge>
                  </div>

                  {/* Status */}
                  <div className="col-span-1 hidden sm:flex items-center gap-1.5">
                    {statusIcons[expense.status]}
                    <span
                      className={`inline-block rounded-md px-2 py-0.5 text-[11px] font-medium ${expenseStatusColors[expense.status]}`}
                    >
                      {formatLabel(expense.status)}
                    </span>
                  </div>

                  {/* Amount */}
                  <div className="col-span-2 hidden md:flex items-center justify-end text-sm font-medium tabular-nums">
                    {formatCurrency(expense.amount)}
                  </div>

                  {/* Date */}
                  <div className="col-span-2 hidden lg:flex items-center gap-1.5 text-xs text-muted-foreground">
                    <Calendar className="size-3.5 shrink-0" />
                    <span className="tabular-nums">{formatDate(expense.date)}</span>
                  </div>

                  {/* Recorded By */}
                  <div className="col-span-1 hidden lg:flex items-center gap-1.5 text-xs text-muted-foreground min-w-0">
                    <User className="size-3.5 shrink-0" />
                    <span className="truncate">{recordedBy?.name ?? "Unknown"}</span>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        {/* Footer totals */}
        <div className="flex items-center justify-end gap-6 border-t bg-muted/40 px-4 py-2.5 text-xs tabular-nums">
          <span className="text-muted-foreground">Verified</span>
          <span className="font-medium text-status-completed-foreground">
            {formatCurrency(totalVerified)}
          </span>
          {totalSubmitted > 0 && (
            <>
              <span className="text-muted-foreground">Submitted</span>
              <span className="font-medium text-priority-medium">
                {formatCurrency(totalSubmitted)}
              </span>
            </>
          )}
          {totalDisputed > 0 && (
            <>
              <span className="text-muted-foreground">Disputed</span>
              <span className="font-medium text-status-blocked-foreground">
                {formatCurrency(totalDisputed)}
              </span>
            </>
          )}
          <span className="text-muted-foreground">Total</span>
          <span className="font-semibold">{formatCurrency(totalAll)}</span>
        </div>
      </div>
    </div>
  );
